section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/mobile-responsive.json",
  "title": "Mobile Responsive",
  "type": "object",
  "required": [
    "artefact_id",
    "breakpoints",
    "container_query_policy",
    "touch_target_min_px",
    "viewport_meta",
    "safe_area_policy",
    "hover_policy",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "breakpoints": {
      "type": "array",
      "minItems": 3,
      "maxItems": 5,
      "description": "{name, min_px}"
    },
    "container_query_policy": {
      "type": "string",
      "minLength": 1
    },
    "touch_target_min_px": {
      "type": "number",
      "minimum": 44
    },
    "viewport_meta": {
      "type": "string",
      "minLength": 1
    },
    "safe_area_policy": {
      "type": "string",
      "minLength": 1
    },
    "hover_policy": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
